RuleSet.GenFile:
--
--	@(#) $GenPackageDir$/$GenFileName$
$MssDoubleDashScriptLicense$
delimiter ////
create function $lower DbSchemaName$.sp_is_tenant_user(
	argTenantId bigint,
	argSecGroupName varchar(64),
	argSecUserId varchar(36) )
returns boolean
not deterministic
begin
	declare retval boolean;
	declare varSecUserId varchar(36);
	declare done boolean default false;
	declare cur1 cursor for $CreateSPIsTenantUserPart1$$CreateSPIsTenantUserPart2$$CreateSPIsTenantUserPart3$$CreateSPIsTenantUserPart4$$CreateSPIsTenantUserPart5$;
	declare cur2 cursor for $CreateSPIsTenantUserPart6$$CreateSPIsTenantUserPart7$$CreateSPIsTenantUserPart8$;
	declare continue handler for not found set done = true;
	select false into retval;
	open cur1;
	read_loop: loop
		fetch cur1 into varSecUserId;
		if done then
			leave read_loop;
		end if;
		select true into retval;
		leave read_loop;
	end loop;
	close cur1;$CreateSPIsTenantUserLoop2$
	return retval;
end;////

RuleSet.GenRule:
if not retval
then
	select false into done;
	open cur2;
	read_loop2: loop
		fetch cur2 into varSecUserId;
		if done then
			leave read_loop2;
		end if;
		select true into retval;
		leave read_loop2;
	end loop;
	close cur2;
end if;
